#!/usr/bin/env bash
# apply-v0.3.3.sh — npm workspaces で @mdss/core を分離（モノレポ化）
# 前提: v0.3.2 の単一パッケージ構成（src/ 直下に parser/schema/components/... がある）
# 冪等: 先頭で packages/core があれば全体を [SKIP]。
#
# 方針（計画③どおり）: アンカー編集ではなく「git mv による移動 ＋ import機械置換 ＋ 設定生成」。
# import置換ロジックはPythonで実施（'./' と '../' の両相対形をカバー）。
# 全文差し替え/新規のファイル（core index・geometry・各種config・Charts.tsx）はbase64で埋め込む。
set -euo pipefail
cd "$(dirname "$0")/.."

# ---------------------------------------------------------------------------
# 0. 冪等ガード
# ---------------------------------------------------------------------------
if [ -d packages/core ]; then
  echo "[SKIP] packages/core が既に存在します。v0.3.3 は適用済みとみなします。"
  exit 0
fi

# git 管理下であることを確認（git mv を使うため）
if ! git rev-parse --is-inside-work-tree >/dev/null 2>&1; then
  echo "[ERROR] git リポジトリ内で実行してください（git mv を使用します）"
  exit 1
fi

echo "=== v0.3.3: monorepo 化を開始します ==="

# ---------------------------------------------------------------------------
# 1. packages/{core,app}/src を作成し、ディレクトリ/ファイルを git mv
# ---------------------------------------------------------------------------
mkdir -p packages/core/src packages/app/src packages/core/src/geometry packages/app/src/parser packages/app/src/schema
git mv src/parser packages/core/src/parser
echo "[OK] moved src/parser -> packages/core/src/parser"
git mv src/schema packages/core/src/schema
echo "[OK] moved src/schema -> packages/core/src/schema"
git mv packages/core/src/parser/inline.tsx packages/app/src/parser/inline.tsx
echo "[OK] moved inline.tsx (core->app: renderInline は ReactNode のため app 残留)"
git mv packages/core/src/schema/roundtrip.test.ts packages/app/src/schema/roundtrip.test.ts
mkdir -p packages/app/src/schema/__snapshots__
git mv packages/core/src/schema/__snapshots__/roundtrip.test.ts.snap packages/app/src/schema/__snapshots__/roundtrip.test.ts.snap
rmdir packages/core/src/schema/__snapshots__ 2>/dev/null || true
echo "[OK] moved roundtrip.test.ts + snapshot (core->app: SLIDE_TEMPLATES/sample.md に依存)"
git mv packages/app/src/components/charts/charts.test.ts packages/core/src/geometry/chart.test.ts 2>/dev/null || \
  git mv src/components/charts/charts.test.ts packages/core/src/geometry/chart.test.ts
echo "[OK] moved charts.test.ts -> core/geometry/chart.test.ts"
git mv src/components packages/app/src/components
echo "[OK] moved src/components -> packages/app/src/components"
git mv src/ai packages/app/src/ai
echo "[OK] moved src/ai -> packages/app/src/ai"
git mv src/help packages/app/src/help
echo "[OK] moved src/help -> packages/app/src/help"
git mv src/hooks packages/app/src/hooks
echo "[OK] moved src/hooks -> packages/app/src/hooks"
git mv src/export packages/app/src/export
echo "[OK] moved src/export -> packages/app/src/export"
git mv src/templates packages/app/src/templates
echo "[OK] moved src/templates -> packages/app/src/templates"
git mv src/samples packages/app/src/samples
echo "[OK] moved src/samples -> packages/app/src/samples"
git mv src/theme packages/app/src/theme
echo "[OK] moved src/theme -> packages/app/src/theme"
git mv src/App.tsx packages/app/src/App.tsx
echo "[OK] moved src/App.tsx -> packages/app/src/App.tsx"
git mv src/main.tsx packages/app/src/main.tsx
echo "[OK] moved src/main.tsx -> packages/app/src/main.tsx"
git mv src/vite-env.d.ts packages/app/src/vite-env.d.ts
echo "[OK] moved src/vite-env.d.ts -> packages/app/src/vite-env.d.ts"
git mv index.html packages/app/index.html
echo "[OK] moved index.html -> packages/app/index.html"
rmdir src 2>/dev/null || true

# ルート直下の旧 vite.config.ts は packages/app/vite.config.ts に役割が移り不要（残すと紛らわしい）。
# vitest 単体実行時に誤って拾われる事故も防ぐため削除する。
if [ -f vite.config.ts ]; then
  git rm -q vite.config.ts
  echo "[OK] 旧 vite.config.ts を削除（packages/app/vite.config.ts に統合済み）"
fi

# ---------------------------------------------------------------------------
# 2. app内の import を @mdss/core へ機械置換（'./' と '../'+ の両相対形）
# ---------------------------------------------------------------------------
python3 - << 'PYEOF2'
import re, pathlib
CORE_MODULES = ['parser/types', 'parser/slideMarkdown', 'parser/slideHeader',
                'parser/deckLint', 'schema/describe', 'schema/registry']
pattern = re.compile(r"from '(\./|(?:\.\./)+)(%s)'" % '|'.join(re.escape(m) for m in CORE_MODULES))
app_root = pathlib.Path('packages/app/src')
files = list(app_root.rglob('*.ts')) + list(app_root.rglob('*.tsx'))
changed = []
for f in files:
    s = f.read_text(encoding='utf-8')
    new = pattern.sub("from '@mdss/core'", s)
    if new != s:
        f.write_text(new, encoding='utf-8')
        changed.append(str(f))
print(f"[OK] import置換: {len(changed)} files")
for c in changed:
    print("     ", c)

# roundtrip.test.ts の parseSlideMarkdown / buildX も @mdss/core へ
rt = pathlib.Path('packages/app/src/schema/roundtrip.test.ts')
s = rt.read_text(encoding='utf-8')
s = s.replace("import { parseSlideMarkdown } from '../parser/slideMarkdown';",
              "import { parseSlideMarkdown } from '@mdss/core';")
s = s.replace("import { buildTypeReferenceTable, buildConstraintRules } from './describe';",
              "import { buildTypeReferenceTable, buildConstraintRules } from '@mdss/core';")
rt.write_text(s, encoding='utf-8')
print("[OK] roundtrip.test.ts の core import を修正")
PYEOF2

# ---------------------------------------------------------------------------
# 3. 新規/全文置換ファイルを書き出し（core index・geometry・Charts.tsx・各種config）
# ---------------------------------------------------------------------------
write_b64() {
  local path="$1"; local content="$2"
  mkdir -p "$(dirname "$path")"
  echo "$content" | base64 -d > "$path"
  echo "[OK] wrote $path"
}
write_b64 'packages/core/src/index.ts' ''
write_b64 'packages/core/src/geometry/chart.ts' ''
write_b64 'packages/core/src/geometry/chart.test.ts' ''
write_b64 'packages/core/package.json' ''
write_b64 'packages/core/tsconfig.json' ''
write_b64 'packages/core/vitest.config.ts' ''
write_b64 'packages/app/package.json' ''
write_b64 'packages/app/tsconfig.json' ''
write_b64 'packages/app/vite.config.ts' ''
write_b64 'packages/app/index.html' ''
write_b64 'packages/app/src/components/charts/Charts.tsx' ''
write_b64 'package.json' ''
write_b64 'tsconfig.json' 'ewogICJmaWxlcyI6IFtdLAogICJjb21tZW50IjogInR5cGVjaGVjayDjga/lkITjg5Hjg4PjgrHjg7zjgrjni6znq4vjgafooYzjgYbvvIhucG0gcnVuIHR5cGVjaGVja++8ieOAguOBk+OBruODleOCoeOCpOODq+OBr0lEReeUqOOBruODgOODn+ODvOOAgiIKfQo='
write_b64 'eslint.config.js' ''
write_b64 '.github/workflows/deploy.yml' ''
write_b64 '.gitignore' 'bm9kZV9tb2R1bGVzCmRpc3QKY292ZXJhZ2UKKi50c2J1aWxkaW5mbwouRFNfU3RvcmUKLmlkZWEKdGVzdC1yZXN1bHRzCnBsYXl3cmlnaHQtcmVwb3J0Cg=='

# ---------------------------------------------------------------------------
# 3.5. 生成ファイルをprettierで整形
#      （base64埋め込み/JSON生成に伴う軽微なフォーマット差異を吸収する）
# ---------------------------------------------------------------------------
npx prettier --write \
  packages/app/index.html \
  packages/app/tsconfig.json \
  packages/core/tsconfig.json \
  packages/core/src/geometry/chart.test.ts \
  packages/core/src/geometry/chart.ts \
  packages/core/src/index.ts \
  packages/app/src/components/charts/Charts.tsx \
  package.json tsconfig.json eslint.config.js \
  2>/dev/null || echo "[WARN] prettier整形をスキップしました（未インストールの可能性）"
echo "[OK] 生成ファイルをprettierで整形"

# node_modules を git 管理から外す（.gitignore 追加に伴う後始末。既に無ければ無害）
git rm -r --cached node_modules >/dev/null 2>&1 || true

# ---------------------------------------------------------------------------
# 4. 依存を再インストール（workspaces解決）
# ---------------------------------------------------------------------------
echo '--- npm install (workspaces) ---'
npm install --silent

# ---------------------------------------------------------------------------
# 5. 段階検証
# ---------------------------------------------------------------------------
echo '--- verify: import残存チェック ---'
if grep -rn "from '\(\./\|\(\.\./\)*\)parser/\(types\|slideMarkdown\|slideHeader\|deckLint\)'\|from '\(\./\|\(\.\./\)*\)schema/\(describe\|registry\)'" packages/app/src/ ; then
  echo '[ERROR] app内にcore参照の相対importが残っています'
  exit 1
fi
echo '[OK] app内にcore参照の相対importは残っていない'

echo '--- (1) core単体テスト（node env・DOM無し）---'
npm run test -w @mdss/core

echo '--- (2) app テスト ---'
npm run test -w @mdss/app

echo '--- (3) typecheck（core/app 独立）---'
npm run typecheck

echo '--- (4) lint（override無し・0 errors）---'
npx eslint packages/core/src packages/app/src

echo '--- (5) build（dist生成）---'
npm run build

echo '--- (6) dist/index.html の相対パス確認 ---'
if grep -q './assets/' packages/app/dist/index.html; then
  echo '[OK] base:'"'"'./'"'"' で相対パス出力を確認'
else
  echo '[WARN] dist/index.html の相対パスを目視確認してください'
fi

echo '=== apply-v0.3.3.sh completed ==='
